import { Video } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Appointment } from '@/types';

interface VideoCallButtonProps {
  appointment?: Appointment | null;
  onStartCall: () => void;
}

export default function VideoCallButton({ appointment, onStartCall }: VideoCallButtonProps) {
  // Only show if there's an online appointment that's confirmed or in-progress
  if (!appointment || appointment.type !== 'online') return null;
  if (!['confirmed', 'in-progress', 'pending'].includes(appointment.status)) return null;

  return (
    <Button
      onClick={onStartCall}
      size="sm"
      className="bg-primary text-primary-foreground hover:bg-primary/90 gap-2"
    >
      <Video className="h-4 w-4" />
      <span className="hidden sm:inline">Join Video Call</span>
      <span className="sm:hidden">Join</span>
    </Button>
  );
}
