"use client";

import { useState, useEffect, useCallback } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { AnimatePresence } from 'framer-motion';
import DashboardLayout from '@/components/layout/DashboardLayout';
import { MessageCircle, UserSearch } from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import ConversationList from '@/components/chat/ConversationList';
import ChatWindow from '@/components/chat/ChatWindow';
import MockVideoCallModal from '@/components/chat/MockVideoCallModal';
import { chatService } from '@/services/chatService';
import { useAuthStore, useChatStore } from '@/store';
import { useNotificationStore } from '@/store';
import { Conversation, Appointment } from '@/types';
import { mockAppointments } from '@/data/mockData';

export default function MessagesPage() {
  const searchParams = useSearchParams();
  const router = useRouter();
  const { user } = useAuthStore();
  const { addNotification } = useNotificationStore();
  const {
    conversations, setConversations,
    activeConversation, setActiveConversation,
    messages, setMessages,
    isLoading, setLoading,
  } = useChatStore();

  const [searchQuery, setSearchQuery] = useState('');
  const [showMobileChat, setShowMobileChat] = useState(false);
  const [showVideoCall, setShowVideoCall] = useState(false);

  const fetchConversations = useCallback(async () => {
    if (!user) return;
    setLoading(true);
    const res = await chatService.getConversations(user.id);
    if (res.success) setConversations(res.data);
    setLoading(false);
  }, [user, setLoading, setConversations]);

  useEffect(() => {
    if (user) fetchConversations();
  }, [user, fetchConversations]);

  useEffect(() => {
    const convId = searchParams.get('conversation');
    if (convId && conversations.length > 0) {
      const conv = conversations.find((c) => c.id === convId);
      if (conv) selectConversation(conv);
    }
  }, [searchParams, conversations]);

  const selectConversation = async (conv: Conversation) => {
    setActiveConversation(conv);
    setShowMobileChat(true);
    const res = await chatService.getMessages(conv.id);
    if (res.success) setMessages(res.data);
    if (user) await chatService.markAsRead(conv.id, user.id);
    fetchConversations();
  };

  const handleVideoCallEnd = (endedAt: string) => {
    setShowVideoCall(false);
    if (activeConversation && user) {
      chatService.sendMessage(
        activeConversation.id,
        activeConversation.doctorId,
        'doctor',
        '📋 Video consultation ended. Your prescription has been sent to your pharmacy. Get well soon!',
        'text'
      ).then((res) => {
        if (res.success) {
          chatService.getMessages(activeConversation.id).then((msgRes) => {
            if (msgRes.success) setMessages(msgRes.data);
          });
        }
      });

      addNotification({
        id: `notif-${Date.now()}`,
        userId: user.id,
        type: 'appointment',
        title: 'Consultation Ended',
        message: 'Your video consultation has ended. Check your messages for the prescription.',
        isRead: false,
        createdAt: endedAt,
      });
    }
  };

  const relatedAppointment: Appointment | null = activeConversation
    ? mockAppointments.find(
        (a) =>
          a.patientId === activeConversation.patientId &&
          a.doctorId === activeConversation.doctorId &&
          a.type === 'online'
      ) ?? null
    : null;

  const filteredConversations = conversations.filter((conv) => {
    if (!searchQuery) return true;
    const doctor = conv.doctor;
    return (
      doctor?.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      doctor?.specialty?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      doctor?.hospital?.toLowerCase().includes(searchQuery.toLowerCase())
    );
  });

  return (
    <DashboardLayout>
      <div className="h-[calc(100vh-8rem)]">
        <Card className="h-full overflow-hidden">
          <div className="flex h-full">
            {/* Conversation list */}
            <div className={`w-full md:w-80 lg:w-96 border-r flex-col ${showMobileChat ? 'hidden md:flex' : 'flex'}`}>
              <ConversationList
                conversations={filteredConversations}
                activeConversationId={activeConversation?.id}
                isLoading={isLoading}
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
                onSelect={selectConversation}
                currentUserId={user?.id ?? ''}
                emptyAction={
                  <Button size="sm" variant="outline" onClick={() => router.push('/patient/doctors')} className="gap-1.5 mt-2">
                    <UserSearch className="h-4 w-4" />Find a Doctor
                  </Button>
                }
              />
            </div>

            {/* Chat area */}
            <div className={`flex-1 flex-col overflow-hidden ${!showMobileChat ? 'hidden md:flex' : 'flex'}`}>
              {activeConversation ? (
                <ChatWindow
                  conversation={activeConversation}
                  appointment={relatedAppointment}
                  onBack={() => { setShowMobileChat(false); setActiveConversation(null); }}
                  onStartVideoCall={() => setShowVideoCall(true)}
                />
              ) : (
                <div className="flex-1 flex items-center justify-center text-center p-8">
                  <div className="space-y-4">
                    <div className="w-20 h-20 mx-auto rounded-full bg-muted flex items-center justify-center">
                      <MessageCircle className="h-10 w-10 text-muted-foreground/40" />
                    </div>
                    <div>
                      <h3 className="text-lg font-semibold text-foreground">Select a conversation</h3>
                      <p className="text-sm text-muted-foreground mt-1 max-w-xs">
                        Chat with doctors and staff about schedules, minor questions, and follow-ups
                      </p>
                    </div>
                    <Button variant="outline" onClick={() => router.push('/patient/doctors')} className="gap-2">
                      <UserSearch className="h-4 w-4" />Find a Doctor to Chat
                    </Button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </Card>
      </div>

      {/* Video call overlay */}
      <AnimatePresence>
        {showVideoCall && activeConversation?.doctor && (
          <MockVideoCallModal
            doctor={activeConversation.doctor}
            onEnd={handleVideoCallEnd}
          />
        )}
      </AnimatePresence>
    </DashboardLayout>
  );
}
