import { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { format, isToday, isYesterday } from 'date-fns';
import {
  Send, Paperclip, MoreVertical, Check, CheckCheck,
  ArrowLeft, Video, Smile, FileText, Image as ImageIcon, X,
  ShieldCheck, CalendarClock,
} from 'lucide-react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { Conversation, Message, Appointment } from '@/types';
import { useAuthStore } from '@/store';
import { chatService } from '@/services/chatService';
import { useChatStore } from '@/store';
import VideoCallButton from './VideoCallButton';

interface ChatWindowProps {
  conversation: Conversation;
  appointment?: Appointment | null;
  onBack: () => void;
  onStartVideoCall: () => void;
}

function formatTime(ts: string) {
  const d = new Date(ts);
  if (isToday(d)) return format(d, 'h:mm a');
  if (isYesterday(d)) return `Yesterday ${format(d, 'h:mm a')}`;
  return format(d, 'MMM d, h:mm a');
}

const EMOJI_LIST = ['😊', '👍', '🙏', '❤️', '😢', '😷', '💊', '🩺', '📋', '✅'];

export default function ChatWindow({ conversation, appointment, onBack, onStartVideoCall }: ChatWindowProps) {
  const { user } = useAuthStore();
  const { messages, addMessage } = useChatStore();
  const [text, setText] = useState('');
  const [isSending, setIsSending] = useState(false);
  const [isTyping, setIsTyping] = useState(false);
  const [showEmoji, setShowEmoji] = useState(false);
  const [attachedFile, setAttachedFile] = useState<{ name: string; type: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const typingTimeoutRef = useRef<ReturnType<typeof setTimeout>>();

  const doctor = conversation.doctor;

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if ((!text.trim() && !attachedFile) || !user || isSending) return;

    const content = attachedFile
      ? `📎 ${attachedFile.name}`
      : text.trim();
    const type = attachedFile
      ? (attachedFile.type.startsWith('image/') ? 'image' : 'file')
      : 'text';

    setIsSending(true);
    setText('');
    setAttachedFile(null);

    const res = await chatService.sendMessage(
      conversation.id,
      user.id,
      user.role as 'patient' | 'doctor',
      content,
      type
    );
    if (res.success) {
      addMessage(res.data);

      // Simulate typing + auto-reply from doctor
      if (user.role === 'patient') {
        const delay = 5000 + Math.random() * 10000;
        setTimeout(() => setIsTyping(true), delay - 3000 > 0 ? delay - 3000 : 0);
        setTimeout(async () => {
          setIsTyping(false);
          const docRes = await chatService.sendMessage(
            conversation.id,
            conversation.doctorId,
            'doctor',
            getAutoResponse(content)
          );
          if (docRes.success) addMessage(docRes.data);
        }, delay);
      }
    }
    setIsSending(false);
  };

  const getAutoResponse = (userMsg: string): string => {
    const lower = userMsg.toLowerCase();
    if (lower.includes('pain') || lower.includes('hurt')) return "I'm sorry to hear you're in pain. Can you describe where exactly and how severe on a scale of 1-10?";
    if (lower.includes('prescription') || lower.includes('medicine')) return "I'll review your medication needs. Please make sure to complete your appointment for me to issue a formal prescription.";
    if (lower.includes('appointment') || lower.includes('schedule')) return "Your appointment details are confirmed. Let's discuss everything in detail during our video consultation.";
    if (lower.includes('result') || lower.includes('lab')) return "Thanks for sharing. I'll review the results and get back to you with my assessment shortly.";
    if (lower.includes('📎')) return "Thanks for sharing the file! I'll review it before our consultation.";
    const responses = [
      "Thank you for the update. I'll take note of this for our consultation.",
      "I understand. Let's discuss this in more detail during our scheduled video call.",
      "Got it! If symptoms worsen, please don't hesitate to reach out immediately.",
      "Thanks for letting me know. Please monitor and update me if anything changes.",
      "I've noted that. We can go through everything during our video consultation.",
    ];
    return responses[Math.floor(Math.random() * responses.length)];
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setAttachedFile({ name: file.name, type: file.type });
    }
    e.target.value = '';
  };

  const handleTextChange = (val: string) => {
    setText(val);
    // Clear typing timeout
    if (typingTimeoutRef.current) clearTimeout(typingTimeoutRef.current);
  };

  return (
    <div className="flex flex-col h-full">
      {/* Header */}
      <div className="px-4 py-3 border-b bg-card flex items-center justify-between shrink-0">
        <div className="flex items-center gap-3">
          <Button variant="ghost" size="icon" className="md:hidden" onClick={onBack}>
            <ArrowLeft className="h-5 w-5" />
          </Button>
          <div className="relative">
            <Avatar>
              <AvatarImage src={doctor?.avatar} />
              <AvatarFallback>{doctor?.name?.charAt(0)}</AvatarFallback>
            </Avatar>
            <span className="absolute bottom-0 right-0 w-3 h-3 rounded-full bg-success border-2 border-background" />
          </div>
          <div>
            <p className="font-semibold text-sm">{doctor?.name}</p>
            <p className="text-xs text-muted-foreground">{doctor?.specialty} · <span className="text-success font-medium">Online</span></p>
          </div>
        </div>
        <div className="flex items-center gap-1">
          <VideoCallButton appointment={appointment} onStartCall={onStartVideoCall} />
          <Button variant="ghost" size="icon">
            <MoreVertical className="h-4 w-4" />
          </Button>
        </div>
      </div>

      {/* Appointment banner */}
      {appointment && appointment.type === 'online' && ['confirmed', 'pending'].includes(appointment.status) && (
        <div className="px-4 py-2 bg-primary/10 border-b border-primary/20 flex items-center gap-2 text-sm shrink-0">
          <CalendarClock className="h-4 w-4 text-primary shrink-0" />
          <span className="text-primary font-medium">
            Your consultation is on {appointment.date} at {appointment.time}
          </span>
          <Button
            size="sm"
            variant="outline"
            className="ml-auto h-7 text-xs border-primary text-primary hover:bg-primary hover:text-primary-foreground"
            onClick={onStartVideoCall}
          >
            <Video className="h-3 w-3 mr-1" />
            Ready to Join?
          </Button>
        </div>
      )}

      {/* Messages */}
      <ScrollArea className="flex-1 px-4 py-4">
        <div className="space-y-3">
          {/* Security note */}
          <div className="flex items-center justify-center gap-1 text-xs text-muted-foreground py-2">
            <ShieldCheck className="h-3 w-3" />
            Messages are secure and private
          </div>

          <AnimatePresence initial={false}>
            {messages.map((msg) => (
              <MessageBubble
                key={msg.id}
                message={msg}
                isOwn={msg.senderId === user?.id}
                formatTime={formatTime}
              />
            ))}
          </AnimatePresence>

          {/* Typing indicator */}
          {isTyping && (
            <motion.div
              initial={{ opacity: 0, y: 6 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0 }}
              className="flex items-end gap-2"
            >
              <Avatar className="h-7 w-7">
                <AvatarImage src={doctor?.avatar} />
                <AvatarFallback className="text-xs">{doctor?.name?.charAt(0)}</AvatarFallback>
              </Avatar>
              <div className="bg-muted rounded-2xl rounded-bl-sm px-4 py-2.5 flex gap-1 items-center">
                <span className="w-2 h-2 bg-muted-foreground/50 rounded-full animate-bounce [animation-delay:0ms]" />
                <span className="w-2 h-2 bg-muted-foreground/50 rounded-full animate-bounce [animation-delay:150ms]" />
                <span className="w-2 h-2 bg-muted-foreground/50 rounded-full animate-bounce [animation-delay:300ms]" />
              </div>
              <span className="text-xs text-muted-foreground">{doctor?.name?.split(' ')[1] ?? 'Doctor'} is typing...</span>
            </motion.div>
          )}

          <div ref={messagesEndRef} />
        </div>
      </ScrollArea>

      {/* Attached file preview */}
      {attachedFile && (
        <div className="mx-4 mb-1 px-3 py-2 bg-muted rounded-lg flex items-center gap-2 text-sm shrink-0">
          {attachedFile.type.startsWith('image/') ? (
            <ImageIcon className="h-4 w-4 text-primary shrink-0" />
          ) : (
            <FileText className="h-4 w-4 text-primary shrink-0" />
          )}
          <span className="truncate flex-1">{attachedFile.name}</span>
          <button onClick={() => setAttachedFile(null)}>
            <X className="h-4 w-4 text-muted-foreground hover:text-foreground" />
          </button>
        </div>
      )}

      {/* Emoji picker */}
      {showEmoji && (
        <div className="mx-4 mb-1 p-2 bg-card border rounded-xl flex flex-wrap gap-1 shrink-0">
          {EMOJI_LIST.map((e) => (
            <button
              key={e}
              className="text-xl hover:scale-125 transition-transform"
              onClick={() => { setText((t) => t + e); setShowEmoji(false); }}
            >
              {e}
            </button>
          ))}
        </div>
      )}

      {/* Input */}
      <form onSubmit={handleSend} className="px-4 py-3 border-t bg-card shrink-0">
        <div className="flex gap-2 items-center">
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="shrink-0"
            onClick={() => setShowEmoji((v) => !v)}
          >
            <Smile className="h-4 w-4" />
          </Button>
          <Button
            type="button"
            variant="ghost"
            size="icon"
            className="shrink-0"
            onClick={() => fileInputRef.current?.click()}
          >
            <Paperclip className="h-4 w-4" />
          </Button>
          <input
            ref={fileInputRef}
            type="file"
            className="hidden"
            accept="image/*,.pdf,.doc,.docx"
            onChange={handleFileSelect}
          />
          <Input
            placeholder="Type a message..."
            value={text}
            onChange={(e) => handleTextChange(e.target.value)}
            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) handleSend(e); }}
            className="flex-1"
          />
          <Button
            type="submit"
            size="icon"
            disabled={(!text.trim() && !attachedFile) || isSending}
            className="shrink-0"
          >
            <Send className="h-4 w-4" />
          </Button>
        </div>
      </form>
    </div>
  );
}

interface BubbleProps {
  message: Message;
  isOwn: boolean;
  formatTime: (ts: string) => string;
}

function MessageBubble({ message, isOwn, formatTime }: BubbleProps) {
  const isFile = message.type === 'file' || message.type === 'image';

  return (
    <motion.div
      initial={{ opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0 }}
      className={`flex ${isOwn ? 'justify-end' : 'justify-start'}`}
    >
      <div
        className={`max-w-[75%] rounded-2xl px-4 py-2.5 ${
          isOwn
            ? 'bg-primary text-primary-foreground rounded-br-sm'
            : 'bg-muted text-foreground rounded-bl-sm'
        }`}
      >
        {isFile ? (
          <div className="flex items-center gap-2">
            {message.type === 'image' ? (
              <ImageIcon className="h-4 w-4 shrink-0" />
            ) : (
              <FileText className="h-4 w-4 shrink-0" />
            )}
            <span className="text-sm underline cursor-pointer">{message.content.replace('📎 ', '')}</span>
          </div>
        ) : (
          <p className="text-sm leading-relaxed">{message.content}</p>
        )}
        <div className={`flex items-center justify-end gap-1 mt-1 ${
          isOwn ? 'text-primary-foreground/70' : 'text-muted-foreground'
        }`}>
          <span className="text-xs">{formatTime(message.timestamp)}</span>
          {isOwn && (
            message.isRead
              ? <CheckCheck className="h-3 w-3" />
              : <Check className="h-3 w-3" />
          )}
        </div>
      </div>
    </motion.div>
  );
}
