import { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import {
  Mic, MicOff, Video, VideoOff, PhoneOff,
  MessageSquare, Maximize2, Minimize2, Users,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { Input } from '@/components/ui/input';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Doctor } from '@/types';

interface MockVideoCallModalProps {
  doctor: Doctor;
  onEnd: (endedAt: string) => void;
}

interface ChatMsg {
  id: string;
  sender: 'me' | 'doctor';
  text: string;
  time: string;
}

export default function MockVideoCallModal({ doctor, onEnd }: MockVideoCallModalProps) {
  const [muted, setMuted] = useState(false);
  const [videoOff, setVideoOff] = useState(false);
  const [showChat, setShowChat] = useState(false);
  const [elapsed, setElapsed] = useState(0);
  const [chatInput, setChatInput] = useState('');
  const [chatMsgs, setChatMsgs] = useState<ChatMsg[]>([
    { id: '1', sender: 'doctor', text: 'Hello! Can you hear me clearly?', time: '00:00' },
  ]);
  const [pip, setPip] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval>>();
  const chatEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    timerRef.current = setInterval(() => setElapsed((s) => s + 1), 1000);
    return () => clearInterval(timerRef.current);
  }, []);

  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [chatMsgs]);

  const formatElapsed = (s: number) => {
    const m = Math.floor(s / 60).toString().padStart(2, '0');
    const sec = (s % 60).toString().padStart(2, '0');
    return `${m}:${sec}`;
  };

  const sendChatMsg = () => {
    if (!chatInput.trim()) return;
    const now = formatElapsed(elapsed);
    setChatMsgs((prev) => [...prev, { id: Date.now().toString(), sender: 'me', text: chatInput, time: now }]);
    setChatInput('');
    // Auto doctor reply
    setTimeout(() => {
      setChatMsgs((prev) => [
        ...prev,
        { id: (Date.now() + 1).toString(), sender: 'doctor', text: 'I see, noted. Let me check your records.', time: formatElapsed(elapsed + 5) },
      ]);
    }, 4000);
  };

  const handleEnd = () => {
    clearInterval(timerRef.current);
    onEnd(new Date().toISOString());
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-black flex flex-col"
    >
      {/* Main video area */}
      <div className="flex-1 relative bg-gray-900">
        {/* Doctor video (mock gradient) */}
        <div className="absolute inset-0 flex items-center justify-center"
          style={{ background: 'linear-gradient(135deg, #1a2a3a 0%, #0d1f2d 100%)' }}>
          {videoOff ? (
            <div className="flex flex-col items-center gap-4 text-white">
              <Avatar className="h-24 w-24">
                <AvatarImage src={doctor.avatar} />
                <AvatarFallback className="text-2xl">{doctor.name.charAt(0)}</AvatarFallback>
              </Avatar>
              <p className="text-lg font-medium">{doctor.name}</p>
              <p className="text-sm text-white/70">Camera is off</p>
            </div>
          ) : (
            <div className="flex flex-col items-center gap-4 text-white">
              <div className="relative">
                <Avatar className="h-32 w-32 ring-4 ring-primary/50">
                  <AvatarImage src={doctor.avatar} />
                  <AvatarFallback className="text-4xl">{doctor.name.charAt(0)}</AvatarFallback>
                </Avatar>
                <span className="absolute bottom-1 right-1 w-4 h-4 bg-green-500 rounded-full border-2 border-black" />
              </div>
              <p className="text-lg font-semibold">{doctor.name}</p>
              <p className="text-sm text-white/60">{doctor.specialty}</p>
            </div>
          )}
        </div>

        {/* PiP self view */}
        <motion.div
          drag
          dragConstraints={{ left: -200, right: 0, top: -400, bottom: 0 }}
          className="absolute bottom-4 right-4 w-32 h-24 rounded-xl overflow-hidden border-2 border-white/20 bg-gray-700 cursor-move flex items-center justify-center"
        >
          {videoOff ? (
            <VideoOff className="h-6 w-6 text-white/50" />
          ) : (
            <div className="w-full h-full bg-gradient-to-br from-primary/40 to-accent/40 flex items-center justify-center">
              <Users className="h-6 w-6 text-white/70" />
            </div>
          )}
          <span className="absolute bottom-1 left-1 text-xs text-white/70">You</span>
        </motion.div>

        {/* Timer & status */}
        <div className="absolute top-4 left-1/2 -translate-x-1/2 bg-black/60 text-white px-4 py-1.5 rounded-full text-sm font-mono flex items-center gap-2">
          <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
          {formatElapsed(elapsed)}
        </div>

        {/* Doctor name overlay */}
        <div className="absolute bottom-4 left-4 bg-black/60 text-white px-3 py-1.5 rounded-lg text-sm">
          <p className="font-medium">{doctor.name}</p>
          <p className="text-xs text-white/70">{doctor.specialty}</p>
        </div>
      </div>

      {/* In-call chat sidebar */}
      {showChat && (
        <motion.div
          initial={{ x: '100%' }}
          animate={{ x: 0 }}
          exit={{ x: '100%' }}
          className="absolute top-0 right-0 h-full w-72 bg-gray-900/95 border-l border-white/10 flex flex-col"
        >
          <div className="p-3 border-b border-white/10 flex items-center justify-between">
            <p className="text-white text-sm font-medium">In-call Chat</p>
            <button onClick={() => setShowChat(false)}>
              <span className="text-white/50 hover:text-white text-lg">×</span>
            </button>
          </div>
          <ScrollArea className="flex-1 p-3">
            <div className="space-y-2">
              {chatMsgs.map((msg) => (
                <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[80%] rounded-xl px-3 py-2 text-sm ${
                    msg.sender === 'me'
                      ? 'bg-primary text-primary-foreground'
                      : 'bg-white/10 text-white'
                  }`}>
                    <p>{msg.text}</p>
                    <p className="text-xs opacity-60 mt-0.5 text-right">{msg.time}</p>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef} />
            </div>
          </ScrollArea>
          <div className="p-3 border-t border-white/10 flex gap-2">
            <Input
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              onKeyDown={(e) => { if (e.key === 'Enter') sendChatMsg(); }}
              placeholder="Message..."
              className="bg-white/10 border-white/20 text-white placeholder:text-white/40"
            />
            <Button size="icon" onClick={sendChatMsg} className="shrink-0">
              <span className="text-sm">→</span>
            </Button>
          </div>
        </motion.div>
      )}

      {/* Controls bar */}
      <div className="bg-gray-900/95 border-t border-white/10 px-6 py-4 flex items-center justify-center gap-4">
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setMuted((v) => !v)}
          className={`h-12 w-12 rounded-full text-white hover:bg-white/20 ${muted ? 'bg-red-500/30 text-red-400' : ''}`}
        >
          {muted ? <MicOff className="h-5 w-5" /> : <Mic className="h-5 w-5" />}
        </Button>
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setVideoOff((v) => !v)}
          className={`h-12 w-12 rounded-full text-white hover:bg-white/20 ${videoOff ? 'bg-red-500/30 text-red-400' : ''}`}
        >
          {videoOff ? <VideoOff className="h-5 w-5" /> : <Video className="h-5 w-5" />}
        </Button>
        <Button
          variant="ghost"
          size="icon"
          onClick={() => setShowChat((v) => !v)}
          className={`h-12 w-12 rounded-full text-white hover:bg-white/20 ${showChat ? 'bg-white/20' : ''}`}
        >
          <MessageSquare className="h-5 w-5" />
        </Button>
        <Button
          size="icon"
          onClick={handleEnd}
          className="h-14 w-14 rounded-full bg-red-600 hover:bg-red-700 text-white"
        >
          <PhoneOff className="h-6 w-6" />
        </Button>
      </div>
    </motion.div>
  );
}
